### Lifecycle Phases
1. **Mounting**: Component created and inserted in the DOM. Runs constructor -> render -> useEffect.
2. **Updating**: Prop or state changes trigger re-render -> useEffect dependency checks.
3. **Unmounting**: Component removed from DOM -> runs cleanups.

### Cleanups in useEffect
Always clean up listeners, intervals, or fetch controllers to avoid memory leaks.
```javascript
useEffect(() => {
  const handleResize = () => console.log(window.innerWidth);
  window.addEventListener('resize', handleResize);

  // Cleanup function
  return () => window.removeEventListener('resize', handleResize);
}, []);
```

### Optimization Tools

- **React.memo**: Memoizes a component; skips re-rendering if props are unchanged.
- **useMemo**: Caches computed values between renders.
- **useCallback**: Caches function instances to prevent child component re-renders when parent states shift.

### Code Splitting
```jsx
import React, { lazy, Suspense } from 'react';
const HeavyCharts = lazy(() => import('./HeavyCharts'));

function Dashboard() {
  return (
    <Suspense fallback={<div>Loading charts...</div>}>
      <HeavyCharts />
    </Suspense>
  );
}
```

### Context API Setup
Avoid prop-drilling by providing data to a subtree.
```jsx
const ThemeContext = React.createContext('dark');

function App() {
  return (
    <ThemeContext.Provider value="light">
      <Toolbar />
    </ThemeContext.Provider>
  );
}

function Toolbar() {
  const theme = React.useContext(ThemeContext);
  return <button className={theme}>Button</button>;
}
```

### Core Buffer & Stream API
Streams handle chunk-based transfers without loading entire files into RAM.
```javascript
const fs = require('fs');
const readableStream = fs.createReadStream('./huge.log');
const writableStream = fs.createWriteStream('./dest.log');

// Pipe streams together
readableStream.pipe(writableStream);
```

### Event Emitter Pattern
```javascript
const EventEmitter = require('events');
const myEmitter = new EventEmitter();

myEmitter.on('buildSuccess', () => console.log('Deploy ready!'));
myEmitter.emit('buildSuccess');
```

### Cluster Module (Horizontal Scaling)
Forks multiple Node.js processes sharing the same port using Round-Robin routing.
```javascript
const cluster = require('cluster');
const http = require('http');
const numCPUs = require('os').cpus().length;

if (cluster.isMaster) {
  for (let i = 0; i < numCPUs; i++) cluster.fork();
} else {
  http.createServer((req, res) => res.end('Done')).listen(8000);
}
```

### Worker Threads
Runs CPU-intensive operations (crypto, image rendering) on background threads, bypassing single-thread blockages.

### Async File Operations
Use Promises instead of blocking synchronous operations:
```javascript
const fs = require('fs/promises');
const path = require('path');

async function readLog() {
  const filePath = path.join(__dirname, 'server.log');
  const data = await fs.readFile(filePath, 'utf8');
  console.log(data);
}
readLog();
```

### Streams vs Buffers
- **Buffer**: Loads entire file into memory (limited to ~2GB).
- **Stream**: Processes small, manageable data chunks.

### Cryptography Module
Signatures, verification, symmetric/asymmetric encryptions:
```javascript
const crypto = require('crypto');

// Hash password
const salt = crypto.randomBytes(16).toString('hex');
const hash = crypto.pbkdf2Sync('password123', salt, 1000, 64, 'sha512').toString('hex');
console.log(hash);
```

### Insecure Randomness
Never use `Math.random()` for secure keys, token generations, or passwords. Always use `crypto.randomBytes()` for cryptographically secure pseudo-random numbers (CSPRNG).

### Routing Basics
Express matches routes using HTTP methods (GET, POST, PUT, DELETE) and URL parameters.
```javascript
const express = require('express');
const app = express();

app.get('/users/:userId/posts/:postId', (req, res) => {
  const { userId, postId } = req.params;
  res.send(`User ${userId}, Post ${postId}`);
});
```

### Middleware Pipeline
Middleware functions have access to the Request (`req`), Response (`res`), and next function (`next`).
```javascript
// Custom Middleware
app.use((req, res, next) => {
  req.requestTime = Date.now();
  next(); // Pass control to next function in stack
});

// Error-handling Middleware (takes 4 parameters)
app.use((err, req, res, next) => {
  res.status(500).json({ error: err.message });
});
```

### CORS (Cross-Origin Resource Sharing)
Security block by browsers that halts script requests to different domains unless headers permit.
```javascript
const cors = require('cors');
app.use(cors({
  origin: 'https://trustedapp.com',
  methods: ['GET', 'POST']
}));
```

### Helmet.js Configuration
Helmet sets HTTP response headers to defend against clickjacking, XSS, and sniff attacks.
```javascript
const helmet = require('helmet');
app.use(helmet());
```

### express-validator Setup
Prevent malicious parameters from reaching controller functions:
```javascript
const { body, validationResult } = require('express-validator');

app.post('/register', [
  body('email').isEmail().normalizeEmail(),
  body('password').isLength({ min: 6 })
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  res.send('Success!');
});
```

### Stateless JWT Auth Flow
Authenticate Express requests using tokens:
```javascript
const jwt = require('jsonwebtoken');

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
}
```

### Prototype Chain
Every object in JavaScript has an internal property link called its Prototype. Properties lookups travel up this chain until found or root is reached (`null`).

### ES6 Class sugar
Classes are syntactic sugar over prototypal inheritance.
```javascript
class Developer {
  constructor(name) { this.name = name; }
  code() { console.log('Typing...'); }
}
const dev = new Developer('Alice');
dev.code();
console.log(Object.getPrototypeOf(dev) === Developer.prototype); // true
```

### Promise Combinators

- **Promise.all**: Waits for all promises to resolve. Fails if *any* reject.
- **Promise.allSettled**: Waits for all promises to resolve or reject, returning full outcomes statuses.
- **Promise.race**: Resolves or rejects as soon as the *first* promise resolves/rejects.
- **Promise.any**: Resolves as soon as the *first* promise resolves. Fails only if all reject.

```javascript
// async/await error handling
async function load() {
  try {
    const data = await fetch('url').then(r => r.json());
  } catch (err) {
    console.error(err);
  }
}
```

### Event Flow Cycles
1. **Capturing Phase**: Event trickles down from Document to Target node.
2. **Target Phase**: Event triggers on targeted element.
3. **Bubbling Phase**: Event bubbles back up to Document (default triggers behavior).

### Event Delegation
Attach a single listener to a parent element to handle events on dynamic child structures.
```javascript
document.querySelector('#parent-list').addEventListener('click', (e) => {
  if (e.target.tagName === 'LI') {
    console.log('Clicked item:', e.target.textContent);
  }
});
```

### Aggregations Flow
Process data sets through multiple transformer pipelines:
```javascript
const stats = await Order.aggregate([
  { $match: { status: 'completed' } },
  { $group: { _id: '$userId', totalSpent: { $sum: '$price' } } },
  { $sort: { totalSpent: -1 } }
]);
```

### Connection Pools
Establishing database connections takes time. A **Connection Pool** maintains a set of open, reusable connections.
- **Node-pg client configuration**:
  ```javascript
  const pool = new Pool({
    max: 20, // Keep up to 20 client connections open
    idleTimeoutMillis: 30000
  });
  ```

### Provider Registries
Providers translate HCL definitions to cloud API requests (e.g. AWS, Azure, GCP).
```hcl
# Resource block
resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "prod-vpc"
  }
}
```

### Variable Input parameters
```hcl
variable "instance_type" {
  type    = string
  default = "t2.micro"
}

# Accessing variable
resource "aws_instance" "app" {
  instance_type = var.instance_type
  ami           = "ami-123456"
}
```

### Jenkinsfile Declarative Pipeline
